 23	
 24	const DetailsRightGrid: FC = () => {
 25	  const { t } = useKubevirtTranslation();
 26	  const { createModal } = useModal();
 27	  const [{ clusterDefaultStorageClass, sortedStorageClasses, virtDefaultStorageClass }, loaded] =
 28	    useDefaultStorageClass();
 29	  const isWindowsOSVolume = useIsWindowsBootableVolume();
 30	
 31	  const {
 32	    instanceTypeVMState,
 33	    isChangingNamespace,
 34	    setInstanceTypeVMState,
 35	    setSelectedStorageClass,
 36	    vmNamespaceTarget,
 37	  } = useInstanceTypeVMStore();
 38	
 39	  const { pvcSource, sshSecretCredentials } = instanceTypeVMState;
 40	
