 45	    });
 46	
 47	    setInstanceTypeVMState({
 48	      payload: initialSysprepData,
 49	      type: instanceTypeActionType.setSysprepConfigMapData,
 50	    });
 51	
 52	    return Promise.resolve();
 53	  };
 54	
 55	  return (
 56	    <DescriptionList className="pf-v6-c-description-list" isHorizontal>
 57	      <VirtualMachineDescriptionItem
 58	        descriptionData={isChangingNamespace ? <Loading /> : vmNamespaceTarget}
 59	        descriptionHeader={t('Project')}
 60	      />
 61	      <VirtualMachineDescriptionItem
 62	        descriptionData={<DiskSize />}
 63	        descriptionHeader={t('Disk size')}
 64	      />
 65	      <VirtualMachineDescriptionItem
 66	        descriptionData={
 67	          loaded ? (
 68	            <InlineFilterSelect
