 76	              options={sortedStorageClasses?.map((scName) => ({ children: scName, value: scName }))}
 77	              setSelected={setSelectedStorageClass}
 78	              toggleProps={{ placeholder: t('Select StorageClass') }}
 79	            />
 80	          ) : (
 81	            <Loading />
 82	          )
 83	        }
 84	        descriptionHeader={t('Storage class')}
 85	      />
 86	      {isWindowsOSVolume ? (
 87	        <SysprepDescriptionItem />
 88	      ) : (
 89	        <>
 90	          <VirtualMachineDescriptionItem
 91	            descriptionData={
 92	              isChangingNamespace ? (
 93	                <Loading />
 94	              ) : (
 95	                sshSecretCredentials?.sshSecretName || t('Not configured')
 96	              )
 97	            }
 98	            onEditClick={() =>
 99	              createModal((modalProps) => (
100	                <SSHSecretModal
101	                  {...modalProps}
102	                  initialSSHSecretDetails={sshSecretCredentials}
103	                  namespace={vmNamespaceTarget}
104	                  onSubmit={setSSHCredentials}
105	                />
106	              ))
107	            }
108	            descriptionHeader={<span id="tour-step-ssh">{t('Public SSH key')}</span>}
109	            isEdit={!isChangingNamespace}
110	          />
111	          <DynamicSSHKeyInjectionInstanceType />
112	        </>
113	      )}
114	    </DescriptionList>
