  1	import React, { FC, useState } from 'react';
  2	
  3	import { useInstanceTypeVMStore } from '@catalog/CreateFromInstanceTypes/state/useInstanceTypeVMStore';
  4	import { instanceTypeVMInitialState } from '@catalog/CreateFromInstanceTypes/state/utils/state';
  5	import {
  6	  instanceTypeActionType,
  7	  SysprepConfigMapData,
  8	} from '@catalog/CreateFromInstanceTypes/state/utils/types';
  9	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 10	import { initialSSHCredentials } from '@kubevirt-utils/components/SSHSecretModal/utils/constants';
 11	import useSysprepConfigMaps from '@kubevirt-utils/components/SysprepModal/hooks/useConfigMaps';
 12	import {
 13	  AUTOUNATTEND,
 14	  generateSysprepConfigMapName,
 15	  UNATTEND,
 16	} from '@kubevirt-utils/components/SysprepModal/sysprep-utils';
 17	import { SysprepModal } from '@kubevirt-utils/components/SysprepModal/SysprepModal';
 18	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 19	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 20	import { ConfigMapModel, modelToGroupVersionKind } from '@kubevirt-utils/models';
 21	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 22	import { Loading } from '@patternfly/quickstarts';
 23	
 24	const SysprepDescriptionItem: FC = () => {
 25	  const { t } = useKubevirtTranslation();
 26	  const { createModal } = useModal();
 27	
 28	  const { instanceTypeVMState, isChangingNamespace, setInstanceTypeVMState, vmNamespaceTarget } =
 29	    useInstanceTypeVMStore();
 30	
 31	  const [sysprepConfigMaps] = useSysprepConfigMaps(vmNamespaceTarget);
 32	  const sysprepInitialData = instanceTypeVMInitialState.sysprepConfigMapData;
 33	  const { sysprepConfigMapData } = instanceTypeVMState;
 34	  const {
 35	    data,
 36	    name: currentSysprepName,
 37	    shouldCreateNewConfigMap,
 38	  } = sysprepConfigMapData || sysprepInitialData;
 39	  const [autounattend, setAutounattend] = useState<string>(data?.autounattend || '');
 40	  const [unattended, setUnattended] = useState<string>(data?.unattended || '');
 41	
 42	  const setSysprepConfigMapData = (newConfigMapData: SysprepConfigMapData) => {
 43	    setInstanceTypeVMState({
 44	      payload: newConfigMapData,
 45	      type: instanceTypeActionType.setSysprepConfigMapData,
 46	    });
 47	
 48	    setInstanceTypeVMState({
 49	      payload: initialSSHCredentials,
 50	      type: instanceTypeActionType.setSSHCredentials,
 51	    });
 52	  };
 53	
 54	  const onSysprepCreation = (unattend: string, autoUnattend: string): Promise<void> => {
 55	    if (!unattend && !autoUnattend) {
 56	      setAutounattend('');
 57	      setUnattended('');
 58	      setSysprepConfigMapData(sysprepInitialData);
 59	      return;
 60	    }
 61	
 62	    setAutounattend(autoUnattend);
 63	    setUnattended(unattend);
 64	    setSysprepConfigMapData({
 65	      data: {
 66	        autounattend: autoUnattend,
 67	        unattended: unattend,
 68	      },
 69	      name: generateSysprepConfigMapName(),
 70	      shouldCreateNewConfigMap: true,
 71	    });
 72	  };
 73	
 74	  const onSysprepSelected = (name: string) => {
 75	    const dataObj = sysprepConfigMaps?.filter((configMap) => configMap.metadata.name === name)[0]
 76	      ?.data;
 77	    const { [AUTOUNATTEND]: autoUnattend, [UNATTEND]: unattend } = dataObj || {};
 78	
 79	    setAutounattend(autoUnattend);
 80	    setUnattended(unattend);
 81	    setSysprepConfigMapData({
 82	      data: {
 83	        autounattend: autoUnattend,
 84	        unattended: unattend,
 85	      },
 86	      name,
 87	      shouldCreateNewConfigMap: false,
 88	    });
 89	  };
 90	
 91	  const sysprepDescription =
 92	    autounattend || unattended ? (
 93	      <ResourceLink
 94	        groupVersionKind={modelToGroupVersionKind(ConfigMapModel)}
 95	        linkTo={false}
 96	        name={currentSysprepName}
 97	      />
 98	    ) : (
 99	      t('Not configured')
100	    );
101	
102	  return (
103	    <VirtualMachineDescriptionItem
104	      onEditClick={() =>
105	        createModal((modalProps) => (
106	          <SysprepModal
107	            {...modalProps}
108	            autoUnattend={autounattend}
109	            namespace={vmNamespaceTarget}
110	            onSysprepCreation={onSysprepCreation}
111	            onSysprepSelected={onSysprepSelected}
112	            shouldCreateConfigMap={shouldCreateNewConfigMap}
113	            sysprepSelected={currentSysprepName}
114	            unattend={unattended}
115	          />
116	        ))
117	      }
118	      descriptionData={isChangingNamespace ? <Loading /> : sysprepDescription}
119	      descriptionHeader={t('Sysprep')}
120	      isEdit={!isChangingNamespace}
121	    />
122	  );
123	};
124	
125	export default SysprepDescriptionItem;

